mapper.select:
SELECT
    id, line_no, data_category_name, data_category_no, source_from, source_type, category_type, priority, version, is_valid, is_delete, create_at, update_at
FROM data_category


        line_no = #{param.lineNo}


        AND data_category_name like CONCAT(#{param.dataCategoryName}, '%')


        AND data_category_no = #{param.dataCategoryNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM data_category


        line_no = #{param.lineNo}


        AND data_category_name like CONCAT(#{param.dataCategoryName}, '%')


        AND data_category_no = #{param.dataCategoryNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0
